// src/declarations.d.ts

// Allow importing .module.css files
declare module '*.module.css';

// Allow importing .module.scss files
declare module '*.module.scss';

// Allow importing images
declare module '*.png';
declare module '*.jpg';
declare module '*.jpeg';
declare module '*.gif';
declare module '*.svg';

